import { 菩薩坐身, 前臂 } from './pusa.js';
import { 彌陀定印, 臂釧 } from '../bujian/index.js';
export const 法波羅蜜 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        // 定印之臂（承彌陀）：肘外而前臂相就於腹前
        骨(() => {
            陽(() => {
                M(-13.4, 28.6);
                C(-14.6, 32.0, -15.2, 37.5, -15.0, 44.6);
                S();
                M(-15.0, 44.6);
                C(-13.4, 50.0, -9.5, 54.4, -5.6, 56.5);
                S();
                M(-10.9, 32.2);
                C(-11.6, 36.5, -12.0, 40.5, -11.9, 43.2);
                S();
                M(-11.9, 43.2);
                C(-10.5, 48.0, -7.8, 52.2, -4.6, 54.6);
                S();
            });
            陰(() => {
                M(13.4, 28.6);
                C(14.6, 32.0, 15.2, 37.5, 15.0, 44.6);
                S();
                M(15.0, 44.6);
                C(13.4, 50.0, 9.5, 54.4, 5.6, 56.5);
                S();
                M(10.9, 32.2);
                C(11.6, 36.5, 12.0, 40.5, 11.9, 43.2);
                S();
                M(11.9, 43.2);
                C(10.5, 48.0, 7.8, 52.2, 4.6, 54.6);
                S();
            });
        });
        彌陀定印(bi, 0, 57.8, 0.95, false);
        // 印上立蓮載篋：莖自印上出，小蓮承梵篋
        衣(() => {
            M(-0.35, 55.2);
            C(-0.5, 52.4, -0.4, 49.8, -0.25, 47.6);
            S();
            M(0.35, 55.2);
            C(0.5, 52.4, 0.42, 49.8, 0.3, 47.6);
            S();
            // 小蓮三瓣
            M(-2.0, 47.6);
            Qk(-1.35, 46.2, -0.5, 45.8);
            S();
            M(2.0, 47.55);
            Qk(1.45, 46.25, 0.6, 45.8);
            S();
            M(-0.5, 45.8);
            Qk(0.05, 45.6, 0.6, 45.8);
            S();
            // 梵篋：橫函束帶
            M(-2.4, 45.5);
            L(2.4, 45.5);
            S();
            M(-2.15, 45.5);
            L(-2.15, 43.3);
            S();
            M(2.15, 45.5);
            L(2.15, 43.3);
            S();
            M(-2.4, 43.3);
            L(2.4, 43.3);
            S();
            細(() => {
                M(-2.15, 44.4);
                L(2.15, 44.4);
                S();
                M(-0.35, 43.3);
                L(-0.35, 45.5);
                S();
                M(0.35, 43.3);
                L(0.35, 45.5);
                S();
            });
        });
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        void 前臂;
        void 細;
    },
});
